import { useState, useEffect } from 'react';
import axios, { AxiosError } from 'axios';
import { useNavigate } from 'react-router-dom';

interface UserFormData {
  name: string;
  email: string;
  role: string;
}

export function useUserForm(userId?: number) {
  const navigate = useNavigate();
  const [formData, setFormData] = useState<UserFormData>({ name: '', email: '', role: 'user' });
  const [roles, setRoles] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [fieldErrors, setFieldErrors] = useState<Partial<Record<keyof UserFormData, string>>>({});

  useEffect(() => {
    axios.get('/api/roles').then(r => setRoles(r.data)).catch(() => setError('Failed to load roles'));
  }, []);

  useEffect(() => {
    if (!userId) return;
    setLoading(true);
    axios.get(`/api/users/${userId}`)
      .then(r => setFormData({ name: r.data.name, email: r.data.email, role: r.data.role }))
      .catch(() => setError('Failed to load user'))
      .finally(() => setLoading(false));
  }, [userId]);

  const setField = (field: keyof UserFormData, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    setFieldErrors(prev => ({ ...prev, [field]: undefined }));
  };

  const validate = (): boolean => {
    const errors: Partial<Record<keyof UserFormData, string>> = {};
    if (!formData.name.trim()) errors.name = 'Name is required';
    if (!formData.email.includes('@')) errors.email = 'Invalid email';
    setFieldErrors(errors);
    return Object.keys(errors).length === 0;
  };

  const submit = async () => {
    if (!validate()) return;
    setLoading(true);
    setError('');
    try {
      if (userId) {
        await axios.put(`/api/users/${userId}`, formData);
      } else {
        await axios.post('/api/users', formData);
      }
      navigate('/users');
    } catch (err) {
      const msg = err instanceof AxiosError ? err.response?.data?.message : 'Something went wrong';
      setError(msg || 'Something went wrong');
    } finally {
      setLoading(false);
    }
  };

  return { formData, roles, loading, error, fieldErrors, setField, submit, isEdit: !!userId };
}

import React from 'react';
import { useUserForm } from '../hooks/useUserForm';

export function UserForm({ userId }: { userId?: number }) {
  const { formData, roles, loading, error, fieldErrors, setField, submit, isEdit } = useUserForm(userId);

  if (loading && isEdit) return <div>Loading...</div>;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    submit();
  };

  return (
    <form onSubmit={handleSubmit}>
      {error && <div className="error">{error}</div>}
      <input value={formData.name} onChange={e => setField('name', e.target.value)} placeholder="Name" />
      {fieldErrors.name && <span className="field-error">{fieldErrors.name}</span>}
      <input value={formData.email} onChange={e => setField('email', e.target.value)} placeholder="Email" />
      {fieldErrors.email && <span className="field-error">{fieldErrors.email}</span>}
      <select value={formData.role} onChange={e => setField('role', e.target.value)}>
        {roles.map(r => <option key={r} value={r}>{r}</option>)}
      </select>
      <button type="submit" disabled={loading}>{isEdit ? 'Update' : 'Create'}</button>
    </form>
  );
}
